import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2, speed):
        return np.linalg.norm(np.array(pos1) - np.array(pos2)) / speed

    def calculate_minimum_remaining_distances(pos, remaining_customers):
        if not remaining_customers:
            return 0
        distances = [calculate_travel_time(pos, customer_pos, truck_speed) for customer_pos in remaining_customers]
        return np.min(distances)

    def calculate_score(travel_time, minimum_remaining_distance, customer_index):
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[customer_index]

        if arrival_time > end_window:
            return float('inf')

        if arrival_time < start_window:
            wait_time = start_window - arrival_time
        else:
            wait_time = 0

        urgency = 1.0 / (end_window - current_time + 1) if end_window > current_time else float('inf')

        return travel_time + 2.0 * wait_time + 0.5 * minimum_remaining_distance - urgency

    best_node = None
    best_score = float('inf')

    for index, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        minimum_remaining_distance = calculate_minimum_remaining_distances(customer_pos, unvisited_customers)
        score = calculate_score(travel_time, minimum_remaining_distance, index)

        if score < best_score:
            best_score = score
            best_node = index

    return best_node
